// 20x15 tile grid. 0 = wall, 1 = floor, 2 = floor (alt color)
// Generated by ellipse: ((c-9.5)/8)^2 + ((r-7)/6)^2 <= 1
function buildOvalMap() {
  const rows = 15, cols = 20;
  const map = [];
  for (let r = 0; r < rows; r++) {
    const row = [];
    for (let c = 0; c < cols; c++) {
      const inEllipse = Math.pow((c - 9.5) / 8, 2) + Math.pow((r - 7) / 6, 2) <= 1;
      // Inner ring for alt color: slightly smaller ellipse
      const inner = Math.pow((c - 9.5) / 5, 2) + Math.pow((r - 7) / 3.5, 2) <= 1;
      row.push(inEllipse ? (inner ? 2 : 1) : 0);
    }
    map.push(row);
  }
  return map;
}

export const OVAL_MAP = buildOvalMap();
